function refColor(i){ return REF_PALETTE[i % REF_PALETTE.length]; }

function avg(arr){ const v = arr.filter(x=>x!==null && x!==undefined && !isNaN(x)); if(!v.length) return null; return v.reduce((a,b)=>a+b,0)/v.length; }
function fmt(n){ return n===null || n===undefined ? '-' : n.toFixed(1); }
function scoreColor(n){
  if(n===null) return 'var(--cream-dim)';
  if(n>=7.5) return 'var(--green)';
  if(n>=5.5) return 'var(--amber)';
  return 'var(--red)';
}
function uniq(arr){ return [...new Set(arr)]; }
function escapeAttr(str){ return String(str).replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

function filteredData(){
  return DATA.filter(d=>{
    if(state.commercial && d.commercial !== state.commercial) return false;
    return true;
  });
}

function setupDropdown(ddId, opts, currentValue, onChange, allLabel){
  const dd = document.getElementById(ddId);
  const btn = dd.querySelector('.dd-btn');
  const label = dd.querySelector('.dd-label');
  const menu = dd.querySelector('.dd-menu');

  const items = [{value:'', text:allLabel}, ...opts.map(o=>({value:o, text:o}))];
  menu.innerHTML = items.map(it=>`<div class="dd-option${it.value===currentValue?' selected':''}" data-value="${escapeAttr(it.value)}">${it.text}</div>`).join('');
  label.textContent = items.find(it=>it.value===currentValue)?.text || allLabel;

  menu.querySelectorAll('.dd-option').forEach(opt=>{
    opt.addEventListener('click', ()=>{
      dd.classList.remove('open');
      onChange(opt.dataset.value);
    });
  });

  if(!btn.dataset.wired){
    btn.dataset.wired = '1';
    btn.addEventListener('click', e=>{
      e.stopPropagation();
      const wasOpen = dd.classList.contains('open');
      document.querySelectorAll('.dd.open').forEach(o=>o.classList.remove('open'));
      if(!wasOpen) dd.classList.add('open');
    });
  }
}

document.addEventListener('click', ()=>{
  document.querySelectorAll('.dd.open').forEach(o=>o.classList.remove('open'));
});
document.addEventListener('keydown', e=>{
  if(e.key === 'Escape') document.querySelectorAll('.dd.open').forEach(o=>o.classList.remove('open'));
});

function populateFilterOptions(){
  const commercials = uniq(DATA.map(d=>d.commercial)).sort();
  const gammes = uniq(DATA.map(d=>d.gamme)).sort();
  setupDropdown('dd-commercial', commercials, state.commercial, (val)=>{ state.commercial = val; renderAll(); }, 'Tous');
  setupDropdown('dd-gamme-comments', gammes, state.commentGamme, (val)=>{ state.commentGamme = val; renderComments(); }, 'Toutes');
}

function renderKPIs(){
  const d = filteredData();
  document.getElementById('kpi-reponses').textContent = d.length;
  document.getElementById('kpi-gammes').textContent = uniq(d.map(x=>x.gamme)).length;
  document.getElementById('kpi-refs').textContent = uniq(d.map(x=>x.gamme+'|'+x.reference)).length;
  document.getElementById('kpi-commerciaux').textContent = uniq(d.map(x=>x.commercial)).length;
  const dates = d.map(x=>x.horodatage).filter(Boolean).sort();
  if(dates.length){
    const opts = {day:'2-digit', month:'short'};
    const f = new Date(dates[0]).toLocaleDateString('fr-FR', opts);
    const l = new Date(dates[dates.length-1]).toLocaleDateString('fr-FR', opts);
    document.getElementById('kpi-periode').textContent = f + ' → ' + l;
  } else {
    document.getElementById('kpi-periode').textContent = '-';
  }
}

function renderGammeList(){
  const d = filteredData();
  const byGamme = {};
  d.forEach(r=>{
    byGamme[r.gamme] = byGamme[r.gamme] || {rows:[], refs:new Set()};
    byGamme[r.gamme].rows.push(r);
    byGamme[r.gamme].refs.add(r.reference);
  });
  const list = Object.entries(byGamme).map(([gamme, obj])=>{
    const potentiel = avg(obj.rows.map(r=>r.potentiel_commercial));
    return {gamme, potentiel, nRefs: obj.refs.size, nReponses: obj.rows.length};
  }).sort((a,b)=> (b.potentiel||0) - (a.potentiel||0));

  const container = document.getElementById('gamme-list');
  if(!list.length){ container.innerHTML = '<div class="empty-state">Aucune donnée pour ces filtres.</div>'; return; }
  container.innerHTML = list.map(item=>{
    const pct = item.potentiel ? (item.potentiel/10*100) : 0;
    const active = state.gamme === item.gamme ? 'active' : '';
    return `<div class="gamme-row ${active}" data-gamme="${item.gamme}">
      <div class="name">${item.gamme}<span class="n">${item.nRefs} référence${item.nRefs>1?'s':''} · ${item.nReponses} réponses</span></div>
      <div class="bar-track"><div class="bar-fill" style="width:${pct}%"></div></div>
      <div class="score" style="color:${scoreColor(item.potentiel)}">${fmt(item.potentiel)}</div>
    </div>`;
  }).join('');
  container.querySelectorAll('.gamme-row').forEach(el=>{
    el.addEventListener('click', ()=>{
      if(el.dataset.gamme !== state.gamme) state.hiddenRefs = new Set();
      state.gamme = el.dataset.gamme;
      renderAll();
      document.getElementById('sec-detail').scrollIntoView({behavior:'smooth', block:'start'});
    });
  });
  if(!state.gamme && list.length) state.gamme = list[0].gamme;
}

function buildRadarChart(canvasId, legendElId, d, gammeRows, big){
  const legendEl = document.getElementById(legendElId);
  legendEl.innerHTML = '';
  const pointFont = big ? 13 : 11;
  const legendFont = big ? 13 : 11;

  try{
    const el = document.getElementById(canvasId);
    const ctx = el.getContext('2d');
    if(typeof Chart === 'undefined') throw new Error('Chart.js indisponible');

    let chartConfig;

    if(state.radarMode === 'references'){
      const byRef = {};
      gammeRows.forEach(r=>{ byRef[r.reference] = byRef[r.reference] || []; byRef[r.reference].push(r); });
      const refNames = Object.keys(byRef);
      const datasets = refNames.map((ref, i)=>{
        const rows = byRef[ref];
        const color = refColor(i);
        const isHidden = state.hiddenRefs.has(ref);
        return {
          label: ref,
          data: REF_DIMS.map(dim => avg(rows.map(r=>r[dim.key])) || 0),
          borderColor: color,
          backgroundColor: 'transparent',
          pointBackgroundColor: color,
          pointRadius: big ? 3.5 : 2.5,
          borderWidth: big ? 2.25 : 1.75,
          hidden: isHidden,
        };
      });
      legendEl.innerHTML = `
        <div class="legend-actions">
          <button type="button" class="legend-action" data-legend-action="all">Tout afficher</button>
          <span class="legend-sep">·</span>
          <button type="button" class="legend-action" data-legend-action="none">Tout masquer</button>
        </div>
        <div class="legend-items">
        ${refNames.map((ref,i)=>{
          const isHidden = state.hiddenRefs.has(ref);
          return `<div class="item${isHidden?' is-hidden':''}" data-legend-ref="${escapeAttr(ref)}" role="button" tabindex="0">
            <span class="sw" style="background:${refColor(i)}"></span>${ref}
          </div>`;
        }).join('')}
        </div>`;
      chartConfig = {
        type:'radar',
        data:{ labels: REF_DIMS.map(x=>x.label), datasets },
        options:{
          responsive:true, maintainAspectRatio:false,
          scales:{ r:{
            min:0, max:10,
            grid:{color:'#EAE5DA'}, angleLines:{color:'#EAE5DA'},
            pointLabels:{color:'#1C1A17', font:{size:pointFont, weight:'600'}},
            ticks:{display:false, backdropColor:'transparent'},
          }},
          plugins:{ legend:{ display:false } }
        }
      };
    } else {
      const gammeVals = GAMME_DIMS.map(dim=>avg(gammeRows.map(r=>r[dim.key])) || 0);
      const portfolioVals = GAMME_DIMS.map(dim=>avg(d.map(r=>r[dim.key])) || 0);
      chartConfig = {
        type:'radar',
        data:{
          labels: GAMME_DIMS.map(x=>x.label),
          datasets:[
            {
              label: state.gamme || 'Gamme',
              data: gammeVals,
              borderColor: '#C4344E',
              backgroundColor: 'rgba(196,52,78,0.14)',
              pointBackgroundColor:'#C4344E',
              borderWidth: big ? 2.5 : 2,
            },
            {
              label:'Moyenne portefeuille',
              data: portfolioVals,
              borderColor:'#B4841F',
              backgroundColor:'rgba(180,132,31,0.08)',
              pointBackgroundColor:'#B4841F',
              borderWidth: big ? 2 : 1.5,
              borderDash:[4,3],
            }
          ]
        },
        options:{
          responsive:true, maintainAspectRatio:false,
          scales:{ r:{
            min:0, max:10,
            grid:{color:'#EAE5DA'}, angleLines:{color:'#EAE5DA'},
            pointLabels:{color:'#1C1A17', font:{size:pointFont, weight:'600'}},
            ticks:{display:false, backdropColor:'transparent'},
          }},
          plugins:{ legend:{ labels:{color:'#78716A', font:{size:legendFont}} } }
        }
      };
    }

    return new Chart(ctx, chartConfig);
  }catch(err){
    const chartWrap = document.getElementById(canvasId).parentElement;
    chartWrap.innerHTML = '<div class="empty-state">Graphique indisponible pour le moment (bibliothèque non chargée). Le tableau ci-contre reste à jour.</div>';
    console.error('Radar chart error:', err);
    return null;
  }
}

function updateRadarLabels(titleId, subId){
  document.getElementById(titleId).textContent = state.radarMode === 'references' ? 'Comparer les références' : 'Profil de la gamme';
  document.getElementById(subId).textContent = state.radarMode === 'references'
    ? 'Échelle 1-10 · une ligne par référence (moyenne des réponses filtrées)'
    : 'Échelle 1-10 · zone dorée = moyenne portefeuille';
}

function renderRadar(d, gammeRows){
  updateRadarLabels('radar-title', 'radar-sub');
  if(radarChartInstance) radarChartInstance.destroy();
  radarChartInstance = buildRadarChart('radar-chart', 'ref-legend', d, gammeRows, false);
}

function renderRadarFullscreen(){
  const d = filteredData();
  const gammeRows = d.filter(r=>r.gamme===state.gamme);
  updateRadarLabels('radar-title-fs', 'radar-sub-fs');
  if(radarChartInstanceFS) radarChartInstanceFS.destroy();
  radarChartInstanceFS = buildRadarChart('radar-chart-fullscreen', 'ref-legend-fullscreen', d, gammeRows, true);
}

function openRadarModal(){
  document.getElementById('radar-modal').classList.add('open');
  document.querySelectorAll('#radar-toggle-fs .seg-btn').forEach(b=>b.classList.toggle('active', b.dataset.mode===state.radarMode));
  renderRadarFullscreen();
}
function closeRadarModal(){
  document.getElementById('radar-modal').classList.remove('open');
}

function renderDetail(){
  const d = filteredData();
  document.getElementById('detail-gamme-name').textContent = state.gamme || '-';
  const gammeRows = d.filter(r=>r.gamme===state.gamme);

  renderRadar(d, gammeRows);

  // References table
  const byRef = {};
  gammeRows.forEach(r=>{
    byRef[r.reference] = byRef[r.reference] || [];
    byRef[r.reference].push(r);
  });
  document.getElementById('detail-refs-sub').textContent = `${Object.keys(byRef).length} référence(s) · moyenne des réponses filtrées`;
  const tbody = document.querySelector('#refs-table tbody');
  const refRows = Object.entries(byRef).map(([ref, rows])=>{
    return {
      ref,
      qp: avg(rows.map(r=>r.qualite_prix)),
      ae: avg(rows.map(r=>r.attractivite_etiquette)),
      fv: avg(rows.map(r=>r.facilite_vendre)),
      rc: avg(rows.map(r=>r.retours_clients)),
    };
  }).sort((a,b)=> (b.qp||0)-(a.qp||0));
  tbody.innerHTML = refRows.map(r=>`<tr>
    <td>${r.ref}</td>
    <td><span class="cell-score" style="color:${scoreColor(r.qp)}">${fmt(r.qp)}</span></td>
    <td><span class="cell-score" style="color:${scoreColor(r.ae)}">${fmt(r.ae)}</span></td>
    <td><span class="cell-score" style="color:${scoreColor(r.fv)}">${fmt(r.fv)}</span></td>
    <td><span class="cell-score" style="color:${scoreColor(r.rc)}">${fmt(r.rc)}</span></td>
  </tr>`).join('') || '<tr><td colspan="5" style="color:var(--cream-dim)">Aucune donnée</td></tr>';
}

function renderCommerciaux(){
  const d = filteredData();
  const allDims = [...REF_DIMS, ...GAMME_DIMS];
  const byComm = {};
  d.forEach(r=>{ byComm[r.commercial] = byComm[r.commercial] || []; byComm[r.commercial].push(r); });
  const container = document.getElementById('comm-grid');
  container.innerHTML = Object.entries(byComm).map(([comm, rows])=>{
    const overall = avg(allDims.flatMap(dim=>rows.map(r=>r[dim.key])));
    const potentiel = avg(rows.map(r=>r.potentiel_commercial));
    const facilite = avg(rows.map(r=>r.facilite_vendre));
    return `<div class="comm-card">
      <div class="name">${comm}</div>
      <div class="row"><span>Moy. générale</span><b style="color:${scoreColor(overall)}">${fmt(overall)}</b></div>
      <div class="row"><span>Potentiel donné</span><b style="color:${scoreColor(potentiel)}">${fmt(potentiel)}</b></div>
      <div class="row"><span>Facilité à vendre</span><b style="color:${scoreColor(facilite)}">${fmt(facilite)}</b></div>
      <div class="row"><span>Réponses</span><b>${rows.length}</b></div>
    </div>`;
  }).join('');
}

