function highlight(text, term){
  if(!term) return text;
  const esc = term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  return text.replace(new RegExp('('+esc+')', 'ig'), '<mark>$1</mark>');
}

function renderComments(){
  const term = state.search.trim().toLowerCase();
  let items = [];
  filteredData().forEach(r=>{
    if(state.commentGamme && r.gamme !== state.commentGamme) return;
    if(r.commentaire_reference && r.commentaire_reference.trim()){
      items.push({gamme:r.gamme, ref:r.reference, commercial:r.commercial, type:'Référence', text:r.commentaire_reference.trim()});
    }
  });
  // dedupe gamme-level comments (same comment repeated per reference row)
  const seenGamme = new Set();
  filteredData().forEach(r=>{
    if(state.commentGamme && r.gamme !== state.commentGamme) return;
    if(r.commentaire_gamme && r.commentaire_gamme.trim()){
      const key = r.gamme+'|'+r.commercial+'|'+r.commentaire_gamme.trim();
      if(!seenGamme.has(key)){
        seenGamme.add(key);
        items.push({gamme:r.gamme, ref:null, commercial:r.commercial, type:'Gamme', text:r.commentaire_gamme.trim()});
      }
    }
  });
  if(term){
    items = items.filter(it => it.text.toLowerCase().includes(term) || it.gamme.toLowerCase().includes(term) || (it.ref||'').toLowerCase().includes(term));
  }
  document.getElementById('comment-count').textContent = items.length + ' commentaire(s)';
  const list = document.getElementById('comment-list');
  if(!items.length){ list.innerHTML = '<div class="empty-state">Aucun commentaire pour ces filtres.</div>'; return; }
  list.innerHTML = items.map(it=>`
    <div class="comment-item">
      <div class="meta">
        <span class="tag-gamme">${it.gamme}</span>
        ${it.ref ? `<span class="tag-ref">- ${it.ref}</span>` : ''}
        <span class="tag-type">${it.type}</span>
        <span class="tag-comm">${it.commercial}</span>
      </div>
      <p>${highlight(it.text, term)}</p>
    </div>
  `).join('');
}

function renderAll(){
  renderKPIs();
  renderGammeList();
  renderDetail();
  renderCommerciaux();
  renderComments();
}

